// Script Continued Below
var ClientTaskerEmailScripts = Class.create();
ClientTaskerEmailScripts.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

	populateTaskerEmailForm: function(){
		//HT - STRY0053832
		var sys_id = this.getParameter('sysparm_sysId');

		//list of values to be sent to the client glideAjax
		var userName = gs.getUserDisplayName();
		var taskNumber;
		var task_name;
		var classification;
		// STRY0071517  - this function takes different glide record types and returns the documents, attachments and shared values for that object
		var tDS = new taskerDocumentScripts();
		var currentAttachDocSettings;

		// STRY0071517 - set recipients
		var aRecipients = [];
		var sRecipients = "";

		//find the record with the sys_id passed as a parameter
		var grTask = new GlideRecord("x_153465_discovert_route_task_instance");
		grTask.addQuery("sys_id", sys_id);
		grTask.query();

		if(grTask.next()){
			// STRY0071517  - this function takes different glide record types and returns the documents, attachments and shared values for that object
			currentAttachDocSettings = tDS.getAttachmentAndDocumentSettings(grTask);

			taskNumber = grTask.number;
			task_name = grTask.task_name;
			classification = grTask.classification.getDisplayValue();
			// STRY0071517 - set recipients
			if(grTask.poc_name){
				aRecipients.push(grTask.poc_name);
			}
			if(grTask.u_internal_contact){
				aRecipients.push(grTask.u_internal_contact);
			}
			if(grTask.point_of_contact){
				aRecipients.push(grTask.point_of_contact);
			}
			sRecipients = aRecipients.join(",");

		}

		var subject = userName + ' has shared the task information for '+ task_name;

		var body = '<p style="margin:-5px 0; line-height:normal; font-size: 11pt; font-family: Calibri, sans-serif;"><span style="font-family: '+"Times New Roman" +', serif; color: #333333;">Hi,</spa></p><br/>'+

		'<p style="margin:-5px 0; line-height:normal; font-size: 11pt; font-family: Calibri, sans-serif;"><span style="font-family: '+"Times New Roman" +', serif; color: #333333;">' + userName + ' has shared the task information for <b>'+ task_name +'.</p><br/>'+

		'<p style="margin:-5px 0; line-height:normal; font-size: 11pt; font-family: Calibri, sans-serif;"><span style="font-family: '+"Times New Roman" +', serif; color: #333333;">'+"The information in this task is classified as <b>"+ classification +'.</p><br/>'+

		'<p style="margin:-5px 0; line-height: normal; font-size: 11pt; font-family: Calibri, sans-serif;"><span style="font-family: '+"Times New Roman" +', serif; color: #333333;">'+"Please see the Attachments on this email for detailed task information.</p><br/>"+

		'<p><hr>'+"Please do not directly reply to this email.<hr></p><br/>";

		//put all the variables collected above into a data object
		var data = {};
			data.exportAttachments = currentAttachDocSettings.sNOWAttachmentsOn;
			data.exportAllSharedAttachments = currentAttachDocSettings.sharingAttachments;
			data.exportMyDocs = currentAttachDocSettings.docIntDocumentsOn;
			data.exportAllSharedDocuments = currentAttachDocSettings.sharingDocuments;
			data.subject = subject.toString();
			data.body = body.toString();
			// STRY0071517 - set recipients
			data.recipients = sRecipients;

			//stringify object for use in GlideAjax
			//HT - STRY0053832
			return JSON.stringify(data);
		},

		type: 'ClientTaskerEmailScripts'
	});
